  function getBrowserSVG(deviceString) {
    if (!deviceString) return DEFAULT_BROWSER_SVG;

    for (const browser in BROWSER_SVGS) {
      if (deviceString.includes(browser)) {
        return BROWSER_SVGS[browser];
      }
    }

    return DEFAULT_BROWSER_SVG;
  }



  function timeAgo(dateString) {
    if (!dateString) return "—";

    const now = new Date();
    const then = new Date(dateString);
    const seconds = Math.floor((now - then) / 1000);

    if (seconds < 10) return "just now";
    if (seconds < 60) return `${seconds} secs ago`;

    const minutes = Math.floor(seconds / 60);
    if (minutes < 60) return `${minutes} min${minutes > 1 ? "s" : ""} ago`;

    const hours = Math.floor(minutes / 60);
    if (hours < 24) return `${hours} hour${hours > 1 ? "s" : ""} ago`;

    const days = Math.floor(hours / 24);
    if (days < 7) return `${days} day${days > 1 ? "s" : ""} ago`;

    return then.toLocaleDateString();
  }

  function visuallyLogoutOtherDevices() {
    const otherContainer = document.getElementById("Active-devices");
    if (!otherContainer) return;

    // only touch OTHER sessions
    const onlineDots = otherContainer.querySelectorAll(".status-dot.online");

    onlineDots.forEach(dot => {
      dot.classList.remove("online");
    });
  }
  const isDesktop = !/android|iphone|ipad|ipod/i.test(navigator.userAgent);


  async function loadActiveSessions() {
    const currentContainer = document.getElementById("current-device");
    const otherContainer = document.getElementById("Active-devices");

    if (!currentContainer || !otherContainer) return;
    saveBtn?.classList.add("hidden");

    try {
      const res = await fetch("/api/sessions", {
        headers: { "X-Requested-With": "XMLHttpRequest" }
      });

      if (!res.ok) throw new Error("Failed to fetch sessions");

      const sessions = await res.json();

      currentContainer.innerHTML = "";
      otherContainer.innerHTML = "";

      if (!sessions.length) {
        otherContainer.innerHTML = `<p class="muted">No active sessions</p>`;
        return;
      }

      const otherSessions = sessions.filter(s => !s.is_current);

      sessions.forEach(s => {
        const lastSeen = timeAgo(s.last_seen);
        const browserSVG = getBrowserSVG(s.device);

        const card = `
            <div class="session-card ${s.is_current ? "current" : "other"}"
                data-uuid="${s.session_uuid}">


              <div class="swipe-content">
              ${
                s.is_current
                  ? "" 
                  : `
                    <div class="swipe-actions">
                      <button
                        class="swipe-delete">
                        <span class="delete-text">Delete</span>
                      </button>
                    </div>
                  `
              }
      
              <div class="swiped-content">     
                <div class="session-icon">
                  <div class="browser-avatar">
                    ${browserSVG}
                    <span class="status-dot ${s.is_online ? "online" : ""}"></span>
                  </div>
                </div>

                <div class="session-content">
                  <div class="session-title">${s.device}</div>
                  <div class="session-location">${s.location || "Unknown location"}</div>
                  <div class="session-time">
                    Last Logged in • ${lastSeen}
                  </div>
                </div>
              </div>
              </div>
          </div>
        `;

        if (s.is_current) {
          currentContainer.insertAdjacentHTML("beforeend", card);
        } else {
          otherContainer.insertAdjacentHTML("beforeend", card);
        }
      });


      if (!otherSessions.length) {
        otherContainer.innerHTML = `<p class="muted">No other active sessions</p>`;
      }
      setupSwipeHintObserver();

    } catch (err) {
      console.error("Session load error:", err);
      otherContainer.innerHTML = `<p class="muted">Failed to load sessions</p>`;
    }

  }


  function lockBodyScroll() {
    document.documentElement.classList.add("swipe-locked");
    document.body.classList.add("swipe-locked");
  }

  function unlockBodyScroll() {
    document.documentElement.classList.remove("swipe-locked");
    document.body.classList.remove("swipe-locked");
  }







let startX = 0;
let startY = 0;
let currentX = 0;

let activeCard = null;
let swipedContent = null;
let actionsWidth = 0;

let dragging = false;
let isHorizontalSwipe = false;
let isVerticalScroll = false;

const SWIPE_ACTIVATION_DISTANCE = 10;
const HARD_DELETE_RATIO = 0.75;


function closeAllSwipes(exceptContent = null) {
  document.querySelectorAll(".session-card.other").forEach(card => {
    const content = card.querySelector(".swiped-content");
    if (!content || content === exceptContent) return;

    content.style.transition = "transform 0.25s cubic-bezier(.2,.8,.2,1)";
    content.style.transform = "translateX(0px)";
    card.classList.remove("open");
  });
}

function resetSwipeState() {
  injectCard?.classList.remove("swipe-lock");
  unlockBodyScroll();

  dragging = false;
  isHorizontalSwipe = false;
  isVerticalScroll = false;
  activeCard = null;
  swipedContent = null;
}

document.addEventListener("touchstart", e => {
  if (isDesktop) return;

  const card = e.target.closest(".session-card.other");
  if (!card) return;

  const content = card.querySelector(".swiped-content");
  const actions = card.querySelector(".swipe-actions");
  if (!content || !actions) return;

  const touch = e.touches[0];

  startX = touch.clientX;
  startY = touch.clientY;
  currentX = startX;

  activeCard = card;
  swipedContent = content;
  actionsWidth = actions.offsetWidth;

  dragging = true;
  isHorizontalSwipe = false;
  isVerticalScroll = false;

  swipedContent.style.transition = "none";
});

document.addEventListener("touchmove", e => {
  if (!dragging || !swipedContent) return;

  const touch = e.touches[0];
  currentX = touch.clientX;

  const dx = currentX - startX;
  const dy = touch.clientY - startY;

  if (!isHorizontalSwipe && !isVerticalScroll) {
    if (
      Math.abs(dx) > SWIPE_ACTIVATION_DISTANCE &&
      Math.abs(dx) > Math.abs(dy)
    ) {
      isHorizontalSwipe = true;

      injectCard?.classList.add("swipe-lock");
      lockBodyScroll();
      closeAllSwipes(swipedContent);
    } 
    else if (Math.abs(dy) > SWIPE_ACTIVATION_DISTANCE) {
      isVerticalScroll = true;
      dragging = false;
      return;
    }
  }

  if (!isHorizontalSwipe) return;

  e.preventDefault();

  let translateX = dx;

  if (translateX > 0) translateX = 0;

  if (translateX < -actionsWidth * 1.2) {
    translateX = -actionsWidth * 1.2;
  }

  swipedContent.style.transform = `translateX(${translateX}px)`;
}, { passive: false });

document.addEventListener("touchend", () => {
  if (!dragging || !swipedContent || !activeCard) {
    resetSwipeState();
    return;
  }

  if (!isHorizontalSwipe) {
    resetSwipeState();
    return;
  }

  swipedContent.style.transition =
    "transform 0.25s cubic-bezier(.2,.8,.2,1)";

  const totalSwipe = currentX - startX;

  // 🔥 HARD SWIPE → INSTANT DELETE
  if (totalSwipe < -actionsWidth * HARD_DELETE_RATIO) {
    const uuid = activeCard.dataset.uuid;

    swipedContent.style.transform = "translateX(-100%)";
    activeCard.style.opacity = "0";

    setTimeout(() => {
      deleteSession(uuid);
    }, 180);
  }

  // 🔹 SOFT SWIPE → OPEN
  else if (totalSwipe < -actionsWidth * 0.35) {
    swipedContent.style.transform = `translateX(${-actionsWidth}px)`;
    activeCard.classList.add("open");
  }

  // 🔹 SNAP BACK
  else {
    swipedContent.style.transform = "translateX(0px)";
    activeCard.classList.remove("open");
  }

  resetSwipeState();
});


  function showSessionMenu(x, y, sessionUUID) {
    removeSessionMenu();

    const menu = document.createElement("div");
    menu.id = "session-menu";
    menu.className = "glass-menu";
    menu.style.left = x + "px";
    menu.style.top = y + "px";

    menu.innerHTML = `
      <button class="danger">Delete session</button>
    `;

    menu.querySelector("button").onclick = () => {
      deleteSession(sessionUUID);
      removeSessionMenu();
    };

    document.body.appendChild(menu);

    setTimeout(() => {
      document.addEventListener("click", removeSessionMenu, { once: true });
    }, 0);
  }

  function removeSessionMenu() {
    document.getElementById("session-menu")?.remove();
  }



  document.addEventListener("contextmenu", (e) => {
    if (!isDesktop) return;

    const card = e.target.closest(".session-card.other");
    if (!card) return;

    e.preventDefault();
    showSessionMenu(e.pageX, e.pageY, card.dataset.uuid);
  });


 

  document.addEventListener("touchstart", e => {
    if (!e.target.closest(".session-card.other")) {
      closeAllSwipes();
      unlockBodyScroll();
      injectCard?.classList.remove("swipe-lock");
    }
  });


  document.addEventListener("click", e => {
    const deleteBtn = e.target.closest(".swipe-delete");
    if (!deleteBtn) return;

    const card = deleteBtn.closest(".session-card.other");
    if (!card) return;

    const uuid = card.dataset.uuid;
    if (!uuid) return;

    deleteSession(uuid);
  });

  
  async function deleteSession(uuid) {
    try {
      const res = await fetch(`/api/sessions/${uuid}`, {
        method: "DELETE",
        headers: {
          "X-CSRFToken": csrfToken,
          "X-Requested-With": "XMLHttpRequest"
        }
      });

      if (!res.ok) throw new Error();

      // 🔥 Optimistic UI update
      const card = document.querySelector(
        `.session-card.other[data-uuid="${uuid}"]`
      );

      if (card) {
        card.remove();
      }

      const otherContainer = document.getElementById("Active-devices");

      // 🧠 If no other sessions left → show message
      const remainingOthers =
        otherContainer.querySelectorAll(".session-card.other").length;

      if (remainingOthers === 0) {
        otherContainer.innerHTML =
          `<p class="muted">No other active sessions</p>`;
      }

    } catch {
      alert("Failed to delete session");
    }
  }




  function logoutAllOtherDevices() {
    showLogoutOtherDevicesModal();
  }


  function showLogoutOtherDevicesModal() {
    // Prevent duplicates
    if (document.getElementById("logoutModal")) return;

    const modal = document.createElement("div");
    modal.id = "logoutModal";
    modal.className = "modal-backdrop";

    modal.innerHTML = `
      <div class="modal-glass">
        <h3>Log out other devices?</h3>
        <p>
          This will immediately log out all other active sessions except this device.
        </p>

        <div class="modal-actions">
          <button class="btn-outline" id="cancelLogout">Cancel</button>
          <button class="btn-danger" id="confirmLogout">Log out</button>
        </div>
      </div>
    `;

    document.body.appendChild(modal);

    // animate in
    modal.classList.add("show")

    const cleanup = () => {
      modal.classList.remove("show");
      setTimeout(() => modal.remove(), 200);
    };

    // cancel
    modal.querySelector("#cancelLogout").onclick = cleanup;

    // click outside
    modal.onclick = (e) => {
      if (e.target === modal) cleanup();
    };

    // confirm
    modal.querySelector("#confirmLogout").onclick = async () => {
      try {
        const res = await fetch("/logout-other-devices", {
          method: "POST",
          headers: {
            "X-Requested-With": "XMLHttpRequest",
            "Content-Type": "application/json",
            "X-CSRFToken": csrfToken
          }
        });

        if (!res.ok) throw new Error();

        cleanup();
        visuallyLogoutOtherDevices();
      } catch {
        cleanup();
        alert("Failed to log out other devices");
      }
    };
  }
 
 
  function open2FAModal() {
    show2FAModal();
  }
  function show2FAModal() {
    if (document.getElementById("twofaModal")) return;

    const modal = document.createElement("div");
    modal.id = "twofaModal";
    modal.className = "modal-backdrop";

    modal.innerHTML = `
      <div class="modal-glass">
        <div id="twofaInner"></div>
      </div>
    `;

    document.body.appendChild(modal);
    modal.classList.add("show");

    const cleanup = () => {
      modal.classList.remove("show");
      setTimeout(() => modal.remove(), 200);
    };

    modal.onclick = (e) => {
      if (e.target !== modal) return;

      if (twoFAStage === "verified") {
        const toggle = document.getElementById("twofaToggle");
        if (toggle) toggle.checked = true;

        showToast("Two-factor authentication enabled", "success");
      }

      cleanup();
    };

    // make accessible globally
    window.close2FAModal = cleanup;

    const inner = modal.querySelector("#twofaInner");

    show2FAIntro(inner);
  }

function show2FAIntro(inner) {
  twoFAStage = "intro";
  inner.innerHTML = `
    <h3>Enable Two-Factor Authentication?</h3>

    <p>
      Add an extra layer of security to your account.
      You’ll first verify your email before setting it up.
    </p>

    <div class="modal-actions">
      <button class="btn-outline" id="cancel2FA">Cancel</button>
      <button class="btn-primary continue2FA" id="continue2FA">Continue</button>
    </div>
  `;

  inner.querySelector("#cancel2FA").onclick = close2FAModal;

  inner.querySelector("#continue2FA").onclick = async (e) => {
    const btn = e.target;

    // ✅ instant feedback
    btn.textContent = "Sending...";
    btn.disabled = true;

    try {
      const res = await fetch("/send-2fa-email-code", {
        method: "POST",
        headers: { "X-CSRFToken": csrfToken }
      });

      // ❌ if failed
      if (!res.ok) {
        btn.textContent = "Continue";
        btn.disabled = false;
        showToast("Failed to send code");
        return;
      }

      // ✅ move to next step
      showOTPViewInit(inner);

    } catch (err) {
      btn.textContent = "Continue";
      btn.disabled = false;
      showToast("Network error");
    }
  };
}

