let qrLibPromise = null;

function loadQRLibrary() {
  if (qrLibPromise) return qrLibPromise;

  qrLibPromise = new Promise((resolve, reject) => {
    const script = document.createElement("script");
    script.src = "https://unpkg.com/qr-code-styling/lib/qr-code-styling.js";
    script.onload = () => resolve();
    script.onerror = reject;
    document.body.appendChild(script);
  });

  return qrLibPromise;
}

function showDisableOTPView(inner) {
  inner.innerHTML = `
    <div class="verify-header">
      <h3>Verify to disable 2FA</h3>
    </div>

    <p>Enter your 6-digit authenticator code</p>

    <div class="otp-row">
      ${Array.from({ length: 6 }).map(() => `
        <div class="otp-box">
          <input type="text" inputmode="numeric" maxlength="1" class="otp-input"/>
        </div>
      `).join("")}
    </div>

    <div class="modal-actions push-downer">
      <button class="btn-outline" id="cancelDisableVerify">Cancel</button>
      <button id="verifyDisableBtn" disabled>Verify</button>
    </div>
  `;

  const boxes = inner.querySelectorAll(".otp-box");
  const inputs = inner.querySelectorAll(".otp-input");
  const verifyBtn = inner.querySelector("#verifyDisableBtn");

  // 🔄 update state
  function updateVerifyState() {
    const code = [...inputs].map(i => i.value).join("");
    const isComplete = code.length === 6;

    verifyBtn.disabled = !isComplete;
    verifyBtn.classList.toggle("valid", isComplete);

  }

  inputs.forEach((input, index) => {
    input.addEventListener("focus", () => {
      boxes[index].classList.add("active");
    });

    input.addEventListener("blur", () => {
      boxes[index].classList.remove("active");
    });

    input.addEventListener("input", (e) => {
      let val = e.target.value.replace(/\D/g, "");

      boxes.forEach(b => b.classList.remove("error"));

      // 📋 paste full code
      if (val.length > 1) {
        val.slice(0, 6).split("").forEach((char, i) => {
          if (inputs[i]) inputs[i].value = char;
        });

        inputs[Math.min(val.length, 5)]?.focus();
        updateVerifyState();
        return;
      }

      input.value = val;

      if (val && inputs[index + 1]) {
        inputs[index + 1].focus();
      }

      updateVerifyState();
    });

    input.addEventListener("keydown", (e) => {
      if (e.key !== "Backspace") return;

      e.preventDefault();

      boxes.forEach(b => b.classList.remove("error"));

      if (input.value) {
        input.value = "";
      } else if (inputs[index - 1]) {
        inputs[index - 1].value = "";
        inputs[index - 1].focus();
      }

      updateVerifyState();
    });
  });

  // 📋 paste handler
  inner.querySelector(".otp-row").addEventListener("paste", (e) => {
    e.preventDefault();

    const pasted = e.clipboardData.getData("text").replace(/\D/g, "").slice(0, 6);

    pasted.split("").forEach((char, i) => {
      if (inputs[i]) inputs[i].value = char;
    });

    inputs[Math.min(pasted.length, 5)]?.focus();
    updateVerifyState();
  });
  inner.querySelector("#cancelDisableVerify").onclick = close2FAModal;

  // ✅ FINAL STEP
  verifyBtn.onclick = async () => {
    const code = [...inputs].map(i => i.value).join("");

    const res = await fetch("/disable-2fa", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-CSRFToken": csrfToken
      },
      body: JSON.stringify({ code })
    });

    if (!res.ok) {
      inputs.forEach(i => i.value = "");
      boxes.forEach(b => b.classList.add("error"));
      return;
    }
    const toggle = document.getElementById("twofaToggle");
    if (toggle) toggle.checked = false;

    close2FAModal();

    showToast("Two-factor authentication disabled", "success");
  };
}


function formatSecret(secret) {
  return secret.match(/.{1,4}/g).join(" ");
}

