function setupCopySecret() {
  const box = document.querySelector(".secret-box");
  const btn = document.querySelector("#copySecret");
  const keyEl = document.querySelector("#secretKey");
  const icon = document.querySelector("#copyIcon");

  if (!box || !btn || !keyEl) return;

  const copy = async () => {
    const text = keyEl.textContent.trim();

    try {
      // 🔥 TRY MODERN API FIRST
      if (navigator.clipboard && window.isSecureContext) {
        await navigator.clipboard.writeText(text);
      } else {
        throw new Error("Fallback needed");
      }

    } catch (err) {
      // 🔥 iOS FALLBACK (this is the fix)
      const textarea = document.createElement("textarea");
      textarea.value = text;

      // Prevent scrolling on iOS
      textarea.style.position = "fixed";
      textarea.style.top = "0";
      textarea.style.left = "0";
      textarea.style.opacity = "0";

      document.body.appendChild(textarea);
      textarea.focus();
      textarea.select();

      try {
        document.execCommand("copy");
      } catch (e) {
        showToast("Copy failed");
        document.body.removeChild(textarea);
        return;
      }

      document.body.removeChild(textarea);
    }

    // ✅ SUCCESS UI
    icon.innerHTML = WhenCopied;
    box.classList.add("copied");

    setTimeout(() => {
      icon.innerHTML = WhenNotcopied;
      box.classList.remove("copied");
    }, 2000);
  };

  box.onclick = copy;

  btn.onclick = (e) => {
    e.stopPropagation();
    copy();
  };
}

document.addEventListener("touchstart", e => {
  if (isDesktop) return;

  const openCard = document.querySelector(".session-card.other.open");
  if (!openCard) return;

  const touchedCard = e.target.closest(".session-card.other");

  // If tapping a DIFFERENT card → close current
  if (touchedCard !== openCard) {
    closeAllSwipes();
    return;
  }

  // If tapping SAME card but not swiping → close it
  if (!dragging) {
    closeAllSwipes();
  }
});



