function runSwipeHintAnimation() {
  if (isDesktop) return;

  const firstCard = document.querySelector(".session-card.other");
  if (!firstCard) return;

  const content = firstCard.querySelector(".swiped-content");
  const actions = firstCard.querySelector(".swipe-actions");
  if (!content || !actions) return;

  const width = actions.offsetWidth;

  // Temporarily disable real swipe interaction
  dragging = false;
  isHorizontalSwipe = false;
  isVerticalScroll = false;

  content.style.transition = "transform 0.45s cubic-bezier(.2,.8,.2,1)";

  // small left swipe
  setTimeout(() => {
    content.style.transform = `translateX(${-width * 0.6}px)`;
  }, 200);

  // back
  setTimeout(() => {
    content.style.transform = "translateX(0px)";
  }, 900);

  // smaller left
  setTimeout(() => {
    content.style.transform = `translateX(${-width * 0.4}px)`;
  }, 1500);

  // fully reset
  setTimeout(() => {
    content.style.transform = "translateX(0px)";
  }, 2100);
}


let swipeHintShown = false;

function setupSwipeHintObserver() {
  if (isDesktop) return;
  if (!injectCard) return;

  const sessionsContainer = document.getElementById("Active-devices");
  if (!sessionsContainer) return;

  let triggered = false;


  injectCard.addEventListener("scroll", () => {
    if (triggered) return;

    const scrollTop = injectCard.scrollTop;
    const triggerPoint = injectCard.scrollHeight * 0.2;

    if (scrollTop > triggerPoint) {
      triggered = true;
      runSwipeHintAnimation();
    }
  });
}


